from urllib.parse import urlparse
import ipaddress
import requests

DEFAULT_TIMEOUT = 10
ALLOWED_SCHEMES = {"http", "https"}

def fetch_url_content(url, timeout=DEFAULT_TIMEOUT, session=None, allowed_schemes=None, max_response_bytes=1024 * 1024):
    allowed_schemes = set(allowed_schemes or ALLOWED_SCHEMES)
    parsed = urlparse(url)

    if parsed.scheme.lower() not in allowed_schemes:
        raise ValueError("Unsupported URL scheme")

    if not parsed.netloc:
        raise ValueError("Invalid URL")

    hostname = parsed.hostname
    if not hostname:
        raise ValueError("Invalid hostname")

    try:
        ip = ipaddress.ip_address(hostname)
        if (
            ip.is_private
            or ip.is_loopback
            or ip.is_link_local
            or ip.is_multicast
            or ip.is_reserved
            or ip.is_unspecified
        ):
            raise ValueError("Disallowed target address")
    except ValueError:
        pass

    client = session or requests.Session()
    headers = {
        "User-Agent": "integration-webhook-fetcher/1.0",
        "Accept": "*/*",
    }

    response = client.get(
        url,
        headers=headers,
        timeout=timeout,
        allow_redirects=False,
        stream=True,
    )
    response.raise_for_status()

    content_length = response.headers.get("Content-Length")
    if content_length and int(content_length) > max_response_bytes:
        raise ValueError("Response too large")

    chunks = []
    total = 0
    for chunk in response.iter_content(chunk_size=8192, decode_unicode=True):
        if not chunk:
            continue
        total += len(chunk.encode("utf-8") if isinstance(chunk, str) else chunk)
        if total > max_response_bytes:
            raise ValueError("Response exceeded maximum allowed size")
        chunks.append(chunk)

    content = "".join(chunks) if chunks and isinstance(chunks[0], str) else b"".join(chunks).decode(response.encoding or "utf-8", errors="replace")
    print(content)
    return content